impl Solution { pub fn push_dominoes(dominoes: String) -> String { let n = dominoes.len(); let mut black_f = vec![0i32; n]; let mut force = 0; for (i, c) in dominoes.chars().enumerate() { if c == 'R' { force = n as i32; } else if c == 'L' { force = 0; } else { force = (force - 1).max(0); } black_f[i] += force; } force = 0; let mut chars: Vec<char> = dominoes.chars().collect(); for i in (0..n).rev() { if chars[i] == 'L' { force = n as i32; } else if chars[i] == 'R' { force = 0; } else { force = (force - 1).max(0); } black_f[i] -= force; } black_f.into_iter().map(|f| if f > 0 { 'R' } else if f < 0 { 'L' } else { '.' }).collect() } }